INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07430', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某受虐婦女回到受虐環境或者提出告訴後，在請求社工協助的過程中反悔，該案主可能有「家醜不外揚」 的想法，只想息事寧人，也或許害怕失去依靠或遭受報復。在這個案例中，所造成工作者的價值衝突不 包括下列那一項？', '["案主最佳利益", "機構規定", "實務工作者個人價值觀與案主價值觀的衝突", "隱私權的尊重"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07431', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某社工進行監護權調查工作，該案主目前與案父同住，母親 3 個月前離家，與案父分居。社工在與案主的 會談中，得知案父半年前疑似有一筆百萬獎金的收入，於是社工在未經證實且未經案父的同意下去求證於 不知情的案母，案母對於案父私吞獎金非常不能諒解，並四處告訴親友。同時，社工認為案父不誠實，而 將此事寫在調查報告中，案父得知此事，一方面深受案母對其不滿之困擾，一方面擔心此事不知會不會影 響最後判決結果，氣憤之下打算對社工提出告訴。在這個案例中，該社工違反了那一種倫理規範？', '["保護案主生命優先原則", "案主自決", "案主最佳利益", "保密原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07432', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關社會工作在我國發展的重要事件說明，何者為錯誤？', '["早期所發展出的十二荒政，已蘊含社會救濟行政的雛型", "民國38年在行政院下成立社會部，設置社會福利司，以更有組織推動社會福利工作", "民國83年所制定的社會福利政策綱領，成為我國日後推展社會福利工作的重要依據", "我國救貧工作自漢朝以迄宋代，所推行之倉廩制度，業已粗具現代社會工作的意義，在本質上就是一 種社區組織與發展的工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07433', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Lowenberg與Dologff（1992）針對社會工作的倫理守則提出一個倫理原則順序表，對於以下四種倫理原', '["隱私守密原則", "最小傷害原則", "差別平等原則", "真誠原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07434', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Dale（1996）提出家長在面對兒童被診斷為障礙的心理歷程中，在「認清方向」的心理反應階段，他會開 始表現出尋求協助、找尋資訊來規劃未來，這時是反應出家長的何項需求？', '["需要同理與情緒支持", "需要宣洩情緒", "需要瞭解與障礙有關的事實狀況", "需要接受規則的協助與指導"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07435', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '案主自決成為社工重要倫理原則之一，是因為社會工作專業發展初期幾位社工前驅與巨擘的努力與貢獻， 以下何者為非？', '["Gordon Hamilton（1937）", "Charles Levy（1966）", "Florence Hollis（1949）", "Mary Richmond（1965）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07436', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關在多元文化社會工作中的反壓迫社會實務工作敘述，何者為正確？', '["反壓迫實務工作提供了個人及家庭實務工作中處理問題的優先順序", "反壓迫實務工作來自實務知識的基礎，缺乏學術論述", "反壓迫實務工作提倡最大介入（maximal intervention），這是因為其對服務提供者與使用者之間權力差 距的瞭解", "「反」（anti）表示反對權力意識型態，社工者應注意此可能會造成二元對立狀態，失去合作與多元發 展可能性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07437', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關精神病理社會工作的描述，何者為錯誤？', '["在三級預防工作中，所謂的次級預防是指針對某特定族群（例如:青少年），提供相關預防性及宣導性 服務", "在該領域工作的社會工作者，須提供多樣性的服務內容，並與其他專業工作者共同組成跨專業合作團隊", "根據社會壓力理論（social stress theory），當個人處在高度壓力情境中，會比沒有處在壓力時，更容易 發生心理衛生的問題", "道德治療法（moral treatment）是17世紀末期，最為盛行的心理衛生處遇模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07438', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Ozawa（1980）檢視工業社工的發展過程，進而提出工業社會之所以願意接受社會工作方案的理由，以下 何者為錯誤？', '["工人從工作中疏離（alienation）的情況一直在擴張", "大量的工人家庭破碎", "工廠管理者想要增進生產力", "工人企圖在工廠內外都獲得較好水準的生活品質"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 16, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07439', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下為社會工作者所訪問的兒童疏忽個案，「我好像走入一個垃圾場，在雜亂的房間中，我看到一個黑 瘦、吃驚的女孩，大約四歲，她身上非常的髒，手腳頭髮都是滿滿的食物碎片或汁液，家裡的環境充滿 垃圾及排泄物…」。這個案例是屬於那一種類型的兒童疏忽？', '["情緒疏忽", "不正當環境", "身體疏忽", "身體虐待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
